class r93193_20774(StrategyBase):
    name = "agent_r93193_20774"
    description = "RSI 低於 30 時表示超賣，高於 70 時表示超買，根據均值回歸理論，超賣時買入，超買時賣出"
    category = "agent"

    def init(self, params: dict[str, Any]) -> None:
        super().init(params)
        self.n = int(params.get("n", 14))
