        # entry: RSI < 30
        # exit: RSI > 70
        if rsi < 30 and self._pos == 0:
            self._pos = 1
            return Signal(action="buy", price=bar.close)
        if rsi > 70 and self._pos == 1:
            self._pos = 0
            return Signal(action="close")
        return None

